function gradeChecker(score) {
  if (score >= 90) {
    return 'A';
  } else if (score >= 80) {
    return 'B';
  } else if (score >= 70) {
    return 'C';
  } else {
    return 'D';
  }
}
console.log(gradeChecker(85)); // consoleには'B'が出力されます

function compareNumbers(firstNum, secondNum) {
  if (firstNum > secondNum) {
    console.log('First is greater');
  } else if (firstNum < secondNum) {
    console.log('First is smaller');
  } else {
    console.log('Both are equal');
  }
}
compareNumbers(3, 5); // consoleには'First is smaller'が出力されます

