function greeting(timeOfDay) {
  if (timeOfDay === 'morning') {
    return 'Good morning';
  } else if (timeOfDay === 'afternoon') {
    return 'Good afternoon';
  } else if (timeOfDay === 'evening') {
    return 'Good evening';
  } else {
    return 'Hello';
  }
}
console.log(greeting('morning')); // consoleには'Good morning'が出力されます

